import java.util.HashMap;
import java.util.Map;

public class RateLimiter {

    public interface RemoteConfig {
        int fetchLimit(String tenant);
    }

    private final Object lock = new Object();
    private final Map<String, Integer> used = new HashMap<>();
    private final RemoteConfig remoteConfig;

    public RateLimiter(RemoteConfig remoteConfig) {
        this.remoteConfig = remoteConfig;
    }

    public boolean allow(String tenant) {
        synchronized (lock) {
            int limit = remoteConfig.fetchLimit(tenant);
            int current = used.getOrDefault(tenant, 0);
            if (current < limit) {
                used.put(tenant, current + 1);
                return true;
            }
            return false;
        }
    }
}
